GROQ_API_URL  = "https://api.groq.com/openai/v1/chat/completions"
MODEL         = "llama-3.3-70b-versatile"
BROWSER_UA    = ("Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
                 "(KHTML, like Gecko) Chrome/122.0.0.0 Safari/537.36")
SHEET_TAB     = "Saved Jobs"
SHEETS_SCOPES = ["https://www.googleapis.com/auth/spreadsheets"]

# ──────────────────────────────────────────────── Job schema ──
# All scrapers produce dicts conforming to this schema.
# Fields marked Optional may be absent (use .get(field) safely).
#
#   role:        str   – job title as-scraped
#   company:     str   – company name (empty string if unknown)
#   location:    str   – city / region string (e.g. "Tel Aviv")
#   link:        str   – canonical job URL (must be unique & valid)
#   source:      str   – board name (e.g. "Greenhouse", "Drushim")
#   posted:      int|None  – unix timestamp of posting, or None
#   description: str|None  – raw description text, or None
#   match_score: int|None  – set by LLM scorer (0-10), initially None
#   reason:      str|None  – one-line LLM reasoning, initially None

def make_job(*, role, company="", location="", link, source,
             posted=None, description=None):
    """Create a normalized job dict. All scrapers should use this."""
    return {
        "role":        role.strip(),
        "company":     company.strip() if company else "",
        "location":    location.strip() if location else "",
        "link":        link.strip(),
        "source":      source,
        "posted":      posted,
        "description": description,
        "match_score": None,
        "reason":      None,
    }

try:
    from zoneinfo import ZoneInfo
    JERUSALEM_TZ = ZoneInfo("Asia/Jerusalem")
except ImportError:
    from datetime import timezone, timedelta
    JERUSALEM_TZ = timezone(timedelta(hours=3))  # fallback

# post-date filter ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ how many seconds back to accept
POST_DATE_SECONDS = {"24h": 86400, "3d": 259200, "7d": 604800,
                     "14d": 1209600, "30d": 2592000}

