def score_jobs_with_llm(jobs, settings, api_key=None):
    """
    Algorithmic job scoring — no LLM, no API key, no rate limits.
    Scores 0-10 based on role type, stack match, and seniority signals.
    api_key param kept for call-site compatibility but is unused.
    """
    if not jobs:
        return []

    min_score = settings.get("minScore", 6)
    max_r     = settings.get("maxResults", 30)

    # ── Role type keywords ────────────────────────────────────────────────
    FULLSTACK_KW = [
        "full stack", "fullstack", "full-stack", "fs developer",
        "fs engineer", "פולסטאק", " fs ", "fs/",
    ]
    BACKEND_KW = [
        "backend", "back end", "back-end", "server-side",
        "api developer", "api engineer", "בקאנד", "back-end developer",
        "node developer", "python developer", "server developer",
    ]
    FRONTEND_KW = [
        "frontend", "front end", "front-end", "ui developer",
        "פרונטאנד", "react developer", "vue developer", "angular developer",
        "web developer",
    ]
    # Generic dev roles that still score above the minimum
    DEV_KW = [
        "developer", "engineer", "programmer", "מפתח", "מתכנת", "מהנדס",
        "מתכנתת", "מפתחת",
    ]

    # ── Stack weights ─────────────────────────────────────────────────────
    # Tier 1 = candidate's primary stack (each 1.0 pt, cap total at 4)
    TIER1 = {
        "react": 1.0, "typescript": 1.0, "python": 1.0,
        "fastapi": 1.0, "node.js": 1.0, "node": 0.8,
        "express": 0.8, "nestjs": 0.8, "next.js": 0.8, "nextjs": 0.8,
    }
    # Tier 2 = supporting skills (each 0.3-0.5 pt)
    TIER2 = {
        "docker": 0.5, "postgresql": 0.5, "postgres": 0.5,
        "firebase": 0.5, "javascript": 0.5, "redis": 0.4,
        "graphql": 0.4, "tailwind": 0.4, "vite": 0.4,
        "rest api": 0.4, "restful": 0.4, "sql": 0.3,
        "jest": 0.3, "aws": 0.3, "ci/cd": 0.3, "git": 0.2, "linux": 0.2,
    }

    # ── Seniority / experience signals ────────────────────────────────────
    JUNIOR_KW = [
        "junior", "entry level", "entry-level", "entry_level",
        "graduate", "fresh graduate", "new grad", "0-1 year", "0-2 year",
        "1-2 year", "up to 1 year", "up to 2 year",
        "student", "intern", "first job", "fresher",
    ]
    MID_KW = [
        "mid level", "mid-level", "middle level",
        "2-3 year", "1-3 year", "2 years", "3 years experience",
    ]

    DIRECT_BOARDS = ["greenhouse", "lever", "ashby"]

    scored = []

    for job in jobs:
        title  = (job.get("role", "")        or "").lower()
        desc   = (job.get("description", "") or job.get("body", "") or "").lower()
        source = (job.get("source", "")      or "").lower()
        text   = f"{title} {desc}"

        pts  = 0.0
        tags = []

        # 1. Role type (0–4 pts) ──────────────────────────────────────────
        if any(k in text for k in FULLSTACK_KW):
            pts += 4.0; tags.append("fullstack")
        elif any(k in text for k in BACKEND_KW):
            pts += 3.0; tags.append("backend")
        elif any(k in text for k in FRONTEND_KW):
            pts += 2.5; tags.append("frontend")
        elif any(k in text for k in DEV_KW):
            pts += 2.0; tags.append("dev")
        else:
            pts += 1.0  # no clear role type

        # 2. Stack match (0–4 pts) ────────────────────────────────────────
        t1 = sum(v for k, v in TIER1.items() if k in text)
        t2 = sum(v for k, v in TIER2.items() if k in text)
        stack_pts = min(4.0, t1 + t2)
        pts += stack_pts
        if stack_pts >= 2.5:
            tags.append("strong-stack")
        elif stack_pts >= 1.0:
            tags.append("partial-stack")

        # 3. Seniority fit (0–1.5 pts) ────────────────────────────────────
        if any(k in text for k in JUNIOR_KW):
            pts += 1.5; tags.append("junior")
        elif any(k in text for k in MID_KW):
            pts += 0.7; tags.append("mid")

        # 4. Source quality bonus (0–0.5 pts) ─────────────────────────────
        # Direct company boards are higher signal than aggregators
        if any(b in source for b in DIRECT_BOARDS):
            pts += 0.5; tags.append("direct-board")

        score = max(0, min(10, round(pts)))

        if score >= min_score:
            job["match_score"] = score
            job["reason"]      = ", ".join(tags) or "dev-role"
            scored.append(job)

    scored.sort(key=lambda j: j["match_score"], reverse=True)
    return scored[:max_r]


